class Solution:
    def minOperations(self, k: int) -> int:
        if k == 1:
            return 0
        # Try different numbers of duplicates
        min_ops = float('inf')
        for m in range(1, int(k**0.5) + 2):
            # m is the number of elements after duplication
            # We need to increase the initial element to at least ceil(k/m)
            ops = (m - 1) + (k + m - 1) // m - 1
            min_ops = min(min_ops, ops)
        return min_ops
